const favoriteBatchRef = useRef({ count: 0, timer: null });

const addToFavoritesWithBatch = (product: Product) => {
  addFavorite(product);
  const batch = favoriteBatchRef.current;
  batch.count++;

  if (batch.timer) clearTimeout(batch.timer);

  batch.timer = setTimeout(() => {
    Toast.show({
      type: 'info',
      text1: `${batch.count} produit(s) ajouté(s) aux favoris ❤️`,
      visibilityTime: 2500
    });
    batch.count = 0;
    batch.timer = null;
  }, 800);
};
```
